// Get stored arrays from global memory
let voltage = global.get("voltage") || [];
let current = global.get("current") || [];
let power = global.get("power") || [];

// Convert payload safely to number
let value = Number(msg.payload);

// Ignore invalid data
if (isNaN(value)) {
    return null;
}

// Message sorting
if (msg.topic === "scada/esp32/voltage1") {
    voltage.push(value);
    global.set("voltage", voltage);
}
else if (msg.topic === "scada/esp32/current1") {
    current.push(value);
    global.set("current", current);
}
else if (msg.topic === "scada/esp32/power1") {
    power.push(value);
    global.set("power", power);
}

// Optional safety: limit array size
if (voltage.length > 1000) voltage.shift();
if (current.length > 1000) current.shift();
if (power.length > 1000) power.shift();

// Do not pass data forward
return msg;

// Get data
let voltage = global.get("voltage") || [];
let current = global.get("current") || [];
let power = global.get("power") || [];

// Calculate averages
let avgV = voltage.reduce((a,b)=>a+b,0)/voltage.length || 0;
let avgC = current.reduce((a,b)=>a+b,0)/current.length || 0;
let avgP = power.reduce((a,b)=>a+b,0)/power.length || 0;

// Create row
let data = {
    time: new Date().toLocaleTimeString(),
    voltage: avgV.toFixed(2),
    current: avgC.toFixed(2),
    power: avgP.toFixed(2)
};

// Table logic (NEW FIX)
let table = flow.get("tableData") || [];

table.push(data);

if (table.length > 24) {
    table.shift();
}

flow.set("tableData", table);

let displayTable = [...table].reverse();

msg.payload = displayTable;

// Clear data after calculation
global.set("voltage", []);
global.set("current", []);
global.set("power", []);

return msg;

// Clear table data
flow.set("tableData", []);

// Clear stored sensor arrays
global.set("voltage", []);
global.set("current", []);
global.set("power", []);

// Send empty table to dashboard
msg.payload = [];

return msg;

let threshold = 5;
let resetThreshold = 4.85;   // hysteresis 

let current = Number(msg.payload);

// Stored values
let isFault = flow.get("oc_fault") || false;
let maxCurrent = flow.get("oc_max") || 0;

// FAULT START
if (current > threshold) {

    if (!isFault) {
        // First time detection
        flow.set("oc_startTime", new Date().toLocaleString());
    }

    isFault = true;

    // Track peak
    if (current > maxCurrent) {
        maxCurrent = current;
    }

    flow.set("oc_fault", true);
    flow.set("oc_max", maxCurrent);

    return null;
}

// FAULT END (with hysteresis) 
if (isFault && current < resetThreshold) {

    let event = {
        type: "OVERCURRENT",
        value: maxCurrent,
        time: flow.get("oc_startTime"),
        clearTime: new Date().toLocaleString(),
        status: "TRIPPED",
        severity: "MEDIUM",
        source: "Node-RED"
    };

    // Reset
    flow.set("oc_fault", false);
    flow.set("oc_max", 0);

    msg.payload = event;
    return msg;
}

return null;

flow.set("faultLog", []);
flow.set("overcurrentState", false);

msg.payload = [];
return msg;

let voltage = Number(msg.payload);

let ov_limit = 280;
let reset_limit = 275;   // hysteresis

// States
let ovActive = flow.get("ovActive") || false;

// Peak trackers
let maxOV = flow.get("maxOV") || 0;

// FAULT START
if (voltage > ov_limit) {

    if (!ovActive) {
        // First detection
        flow.set("ov_startTime", new Date().toLocaleString());
        maxOV = voltage;
    }

    ovActive = true;

    // Track peak voltage
    if (voltage > maxOV) {
        maxOV = voltage;
    }

    flow.set("ovActive", true);
    flow.set("maxOV", maxOV);

    return null;
}

// FAULT END (WITH HYSTERESIS) 
if (ovActive && voltage < reset_limit) {

    let event = {
        type: "OVERVOLTAGE",
        value: maxOV,
        time: flow.get("ov_startTime"),
        clearTime: new Date().toLocaleString(),
        status: "TRIPPED",
        severity: "MEDIUM",
        source: "Node-RED"
    };

    // Reset
    flow.set("ovActive", false);
    flow.set("maxOV", 0);

    msg.payload = event;
    return msg;
}

return null;

// VALIDATE
if (!msg.payload) return null;

let log = flow.get("faultLog") || [];
let entry = {};

// STRING (ESP32 FAULT) 
if (typeof msg.payload === "string") {

    let type = msg.payload;

    let severity = "LOW";
    let status = "ACTIVE";

    if (type === "SHORT_CIRCUIT") {
        severity = "HIGH";
        status = "TRIPPED";
    }
    else if (type === "OVERCURRENT" || type === "OVERVOLTAGE" || type === "UNDERVOLTAGE") {
        severity = "MEDIUM";
        status = "ACTIVE";
    }

    entry = {
        time: new Date().toLocaleString(),
        clearTime: "-",   // NEW
        type: type,
        value: "-",
        status: status,
        severity: severity,
        source: "ESP32"
    };
}

//  OBJECT (NODE-RED EVENTS) 
else if (typeof msg.payload === "object") {

    entry = {
        time: msg.payload.time || new Date().toLocaleString(),
        clearTime: msg.payload.clearTime || "-",   // NEW
        type: msg.payload.type || "UNKNOWN",
        value: msg.payload.value ?? "-",
        status: msg.payload.status || "ACTIVE",
        severity: msg.payload.severity || "LOW",
        source: msg.payload.source || "Node-RED"
    };
}

// PREVENT DUPLICATE ENTRIES 
let last = log[log.length - 1];
if (last && last.type === entry.type && last.status === entry.status) {
    return null;
}

//  ADD LOG 
log.push(entry);

// LIMIT
if (log.length > 50) log = log.slice(-50);

flow.set("faultLog", log);

//  OUTPUT 
msg.payload = [...log].reverse();

return msg;

let voltage = Number(msg.payload);

let uv_limit = 180;      // trip threshold
let reset_limit = 185;   // hysteresis reset

// States
let uvActive = flow.get("uvActive") || false;

// Min tracker (important difference from OV)
let minUV = flow.get("minUV") || voltage;

//  FAULT START / CONTINUE
if (voltage < uv_limit) {

    if (!uvActive) {
        // First detection
        flow.set("uv_startTime", new Date().toLocaleString());
        minUV = voltage;
    }

    uvActive = true;

    // Track minimum voltage
    if (voltage < minUV) {
        minUV = voltage;
    }

    flow.set("uvActive", true);
    flow.set("minUV", minUV);

    return null;
}

// FAULT END (WITH HYSTERESIS)
if (uvActive && voltage > reset_limit) {

    let event = {
        type: "UNDERVOLTAGE",
        value: minUV,   // lowest voltage reached
        time: flow.get("uv_startTime"),
        clearTime: new Date().toLocaleString(),
        status: "TRIPPED",
        severity: "MEDIUM",
        source: "Node-RED"
    };

    // Reset
    flow.set("uvActive", false);
    flow.set("minUV", voltage);

    msg.payload = event;
    return msg;
}

return null;

// ===== GET STORED STATE =====
let data = flow.get("sldData") || {
    voltage: 0,
    current: 0,
    relay: "OFF",     // actual breaker position
    status: "UNKNOWN",// system condition
    fault: "NORMAL"
};

// ===== PROCESS BASED ON TOPIC =====

// Voltage
if (msg.topic === "scada/esp32/voltage1") {
    data.voltage = Number(msg.payload);
    flow.set("sldData", data);
    return { topic: "voltage", payload: data.voltage };
}

// Current
else if (msg.topic === "scada/esp32/current1") {
    data.current = Number(msg.payload);
    flow.set("sldData", data);
    return { topic: "current", payload: data.current };
}

// Relay Position (NEW - IMPORTANT)
else if (msg.topic === "scada/esp32/relay_state1") {
    data.relay = msg.payload;
    flow.set("sldData", data);
    return { topic: "relay", payload: data.relay };
}

// System Status (NORMAL / TRIPPED / RECLOSING / LOCKOUT)
else if (msg.topic === "scada/esp32/status1") {
    data.status = msg.payload;
    flow.set("sldData", data);
    return { topic: "status", payload: data.status };
}

// Fault
else if (msg.topic === "scada/esp32/fault1") {
    data.fault = msg.payload;
    flow.set("sldData", data);
    return { topic: "fault", payload: data.fault };
}

return null;

if (msg.topic === "scada/relay1") {
    return msg; // pass only CB control messages
} else {
    return null; // ignore everything else
}
